import { useState } from 'react';
import { ArrowRight, Gamepad2, Globe, Database, Leaf, GraduationCap, BookOpen, X } from 'lucide-react';
import SectionHeader from './SectionHeader';
import { useApp } from '../context/AppContext';
import t from '../i18n/translations';

const icons = [GraduationCap, BookOpen, Gamepad2, Gamepad2, Database, Leaf];

const stylesData = [
  { tagClass:'bg-teal/10 text-teal2', borderHover:'hover:border-teal/25', dot:'bg-teal', accent:'border-teal/20' },
  { tagClass:'bg-soft-blue/10 text-blue-500', borderHover:'hover:border-blue-400/25', dot:'bg-blue-400', accent:'' },
  { tagClass:'bg-amber/10 text-amber2', borderHover:'hover:border-amber/25', dot:'bg-amber', accent:'' },
  { tagClass:'bg-amber/10 text-amber2', borderHover:'hover:border-amber/25', dot:'bg-amber', accent:'' },
  { tagClass:'bg-lav/20 text-purple-500', borderHover:'hover:border-lav/35', dot:'bg-lav', accent:'' },
  { tagClass:'bg-coral/10 text-coral', borderHover:'hover:border-coral/25', dot:'bg-coral', accent:'' },
];

const chipsEn = [
  ['React','Node.js','SQL Server','JWT'],
  ['HTML','CSS','JavaScript'],
  ['Game Engine','Graphics','Docs'],
  ['Textures','Lighting','UX'],
  ['MS Access','Relational DB','Team ×4'],
  ['ESG','Strategy','Forage'],
];
const chipsAr = [
  ['React','Node.js','SQL Server','JWT'],
  ['HTML','CSS','JavaScript'],
  ['محرك اللعبة','رسومات','توثيق'],
  ['تكسچر','إضاءة','تجربة مستخدم'],
  ['MS Access','قاعدة بيانات','فريق ×4'],
  ['الاستدامة','استراتيجية','Forage'],
];

// Examor details modal content
const examorDetails = {
  en: {
    title: 'Examor — Full Stack Exam Platform',
    stack: 'React.js + Node.js + Express.js + SQL Server + JWT',
    features: [
      'Role-based system: Admin / Doctor / Student',
      'MCQ, True/False, Essay question types',
      'Auto-grading for objective questions',
      'Unique exam code generation',
      'JWT authentication + bcrypt password hashing',
      'SQL Injection protection via parameterized queries',
      '20+ REST API endpoints',
      'Timer with auto-submit',
      '3 institutions: Sadat Academy, Tebah, AIC',
    ],
    status: '🔄 In Progress — Frontend dashboards remaining',
  },
  ar: {
    title: 'Examor — منصة امتحانات Full Stack',
    stack: 'React.js + Node.js + Express.js + SQL Server + JWT',
    features: [
      'نظام أدوار: Admin / Doctor / Student',
      'أنواع أسئلة: MCQ + صح/خطأ + مقالي',
      'تصحيح تلقائي للأسئلة الموضوعية',
      'توليد كود فريد لكل امتحان',
      'JWT + bcrypt لحماية كلمات المرور',
      'حماية من SQL Injection',
      '+20 API endpoint',
      'عداد تنازلي مع تسليم تلقائي',
      '3 مؤسسات: أكاديمية السادات، طيبة، AIC',
    ],
    status: '🔄 قيد التطوير — لوحات التحكم متبقية',
  },
};

function ExamorModal({ onClose, dark, lang }) {
  const d = examorDetails[lang];
  const bg = dark ? 'bg-[#13131e]' : 'bg-parchment';
  const textBase = dark ? 'text-white' : 'text-ink';
  const textMuted = dark ? 'text-white/60' : 'text-muted2';
  return (
    <div className="fixed inset-0 z-50 bg-black/60 backdrop-blur-sm flex items-center justify-center p-4" onClick={onClose}>
      <div className={`relative max-w-lg w-full ${bg} rounded-2xl p-7 shadow-2xl`} onClick={e => e.stopPropagation()}>
        <button onClick={onClose} className="absolute top-4 right-4 text-muted hover:text-amber transition-colors"><X size={20}/></button>
        <div className="flex items-center gap-2 mb-1">
          <span className="text-[.68rem] font-semibold uppercase tracking-wider bg-teal/10 text-teal2 px-2 py-0.5 rounded-full">Full Stack</span>
          <span className="text-[.65rem] font-semibold bg-amber/10 text-amber2 px-2 py-0.5 rounded-full">🔄 In Progress</span>
        </div>
        <h3 className={`font-serif-display text-2xl tracking-tight mt-2 mb-1 ${textBase}`}>{d.title}</h3>
        <p className="text-[.75rem] text-amber font-mono mb-4">{d.stack}</p>
        <ul className="space-y-2 mb-4">
          {d.features.map((f, i) => (
            <li key={i} className={`flex items-start gap-2 text-[.85rem] ${textMuted}`}>
              <span className="text-teal mt-0.5 flex-shrink-0">✓</span>{f}
            </li>
          ))}
        </ul>
        <div className={`text-[.78rem] font-medium px-3 py-2 rounded-lg bg-amber/8 text-amber2`}>{d.status}</div>
      </div>
    </div>
  );
}

export default function Projects() {
  const { dark, lang } = useApp();
  const tr = t[lang];
  const [showExamor, setShowExamor] = useState(false);

  const bg = dark ? 'bg-[#0f0f14]' : 'bg-parchment';
  const cardBg = dark ? 'bg-[#13131e]' : 'bg-cream';
  const chipBg = dark ? 'bg-[#1a1a28]' : 'bg-parchment';
  const chips = lang === 'ar' ? chipsAr : chipsEn;

  return (
    <>
      <section id="projects" className={`py-24 px-[5%] ${bg} transition-colors duration-300`}>
        <SectionHeader tag={tr.projTag} title={tr.projTitle} />
        <div className="grid md:grid-cols-2 gap-5">
          {tr.projects.map((p, i) => {
            const Icon = icons[i];
            const s = stylesData[i];
            const isExamor = i === 0;
            return (
              <div key={i}
                onClick={isExamor ? () => setShowExamor(true) : undefined}
                className={`reveal ${i===1?'delay-1':i===2?'delay-2':i===3?'delay-3':''} relative ${cardBg} rounded-2xl p-10 border-[1.5px] ${isExamor?'border-teal/20':'border-transparent'} transition-all duration-300 flex flex-col ${s.borderHover} hover:-translate-y-1.5 hover:shadow-xl group overflow-hidden ${isExamor?'cursor-pointer':''}`}>
                <div className={`absolute w-28 h-28 rounded-full ${s.dot} opacity-[.13] -top-7 -right-7 pointer-events-none`} />
                <div className="absolute top-4 right-5 font-serif-display text-5xl italic text-ink/[.04] leading-none">0{i+1}</div>

                <div className="flex items-start justify-between mb-4">
                  <span className={`inline-flex items-center gap-1.5 text-[.67rem] font-semibold tracking-wider uppercase px-3 py-1 rounded-full ${s.tagClass}`}>
                    <Icon size={11}/> {p.tag}
                  </span>
                  {isExamor && <span className="text-[.6rem] font-semibold bg-teal/10 text-teal2 px-2 py-0.5 rounded-full">{tr.inProgress}</span>}
                </div>

                <h3 className={`font-serif-display text-xl tracking-tight mb-3 leading-snug ${dark?'text-white':'text-ink'}`}>{p.title}</h3>
                <p className={`text-[.87rem] leading-[1.75] flex-1 ${dark?'text-white/55':'text-muted2'}`}>{p.desc}</p>

                {/* Examor stack pills */}
                {isExamor && (
                  <div className="flex gap-1.5 flex-wrap mt-3">
                    {['React','Node.js','SQL Server','JWT','Express'].map(tech => (
                      <span key={tech} className="text-[.62rem] font-mono px-2 py-0.5 bg-teal/8 text-teal2 rounded-full border border-teal/15">{tech}</span>
                    ))}
                  </div>
                )}

                <div className={`flex items-center justify-between mt-5 pt-4 border-t ${dark?'border-white/[.07]':'border-ink/[.07]'}`}>
                  <div className="flex gap-1.5 flex-wrap">
                    {chips[i].map(c => (
                      <span key={c} className={`text-[.67rem] font-medium px-2 py-0.5 ${chipBg} rounded ${dark?'text-white/40':'text-muted'}`}>{c}</span>
                    ))}
                  </div>
                  <div className={`w-7 h-7 border-[1.5px] rounded-lg flex items-center justify-center transition-all group-hover:border-amber group-hover:text-amber ${dark?'border-white/10 text-white/30':'border-ink/10 text-muted'}`}>
                    {isExamor ? <span className="text-[.6rem] font-bold">↗</span> : <ArrowRight size={13}/>}
                  </div>
                </div>
              </div>
            );
          })}
        </div>
      </section>

      {showExamor && <ExamorModal onClose={() => setShowExamor(false)} dark={dark} lang={lang} />}
    </>
  );
}
